const updateSocialProfile = `-- name: UpdateSocialProfile :one
UPDATE social_profiles SET
    display_name = $2,
    bio = $3,
    avatar_visibility = $4,
    bio_visibility = $5,
    followed_shows_visibility = $6,
    top_podcasts_visibility = $7,
    stats_visibility = $8,
    history_visibility = $9,
    presence_visibility = $10,
    require_follow_approval = $11,
    social_push_disabled = $12,
    hide_from_discovery = $13,
    updated_at = now()
WHERE user_id = $1
RETURNING user_id, handle, display_name, bio, terms_version, avatar_visibility, bio_visibility, followed_shows_visibility, top_podcasts_visibility, stats_visibility, history_visibility, presence_visibility, created_at, updated_at, require_follow_approval, replies_seen_at, social_push_disabled, hide_from_discovery, digest_sent_at, curator
`

type UpdateSocialProfileParams struct {
	UserID                  int64
	DisplayName             string
	Bio                     string
	AvatarVisibility        int16
	BioVisibility           int16
	FollowedShowsVisibility int16
	TopPodcastsVisibility   int16
	StatsVisibility         int16
	HistoryVisibility       int16
	PresenceVisibility      int16
	RequireFollowApproval   bool
	SocialPushDisabled      int64
	HideFromDiscovery       bool
}

// The handle is immutable and deliberately absent here (ADR-0005).
func (q *Queries) UpdateSocialProfile(ctx context.Context, arg UpdateSocialProfileParams) (SocialProfile, error) {
	row := q.db.QueryRow(ctx, updateSocialProfile,
		arg.UserID,
		arg.DisplayName,
		arg.Bio,
		arg.AvatarVisibility,
		arg.BioVisibility,
		arg.FollowedShowsVisibility,
		arg.TopPodcastsVisibility,
		arg.StatsVisibility,
		arg.HistoryVisibility,
		arg.PresenceVisibility,
		arg.RequireFollowApproval,
		arg.SocialPushDisabled,
		arg.HideFromDiscovery,
	)
	var i SocialProfile
	err := row.Scan(
		&i.UserID,
		&i.Handle,
		&i.DisplayName,
		&i.Bio,
		&i.TermsVersion,
		&i.AvatarVisibility,
		&i.BioVisibility,
		&i.FollowedShowsVisibility,
		&i.TopPodcastsVisibility,
		&i.StatsVisibility,
		&i.HistoryVisibility,
		&i.PresenceVisibility,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.RequireFollowApproval,
		&i.RepliesSeenAt,
		&i.SocialPushDisabled,
		&i.HideFromDiscovery,
		&i.DigestSentAt,
		&i.Curator,
	)
	return i, err
}

